itemId = self.view.params.value
if not itemId:
	empty = {"rows": []}
	self.view.custom.state = {"selected": dict(empty), "editDraft": dict(empty)}
	return
rawRows = BlueRidge.Parts.Eligibility.listByItem(itemId) or []
loaded = []
for r in rawRows:
	r = r or {}
	loaded.append({
		"id":                  r.get("Id"),
		"locationId":          r.get("LocationId"),
		"locationLabel":       (r.get("LocationCode") or "") + " \u2014 " + (r.get("LocationName") or "") + " (" + (r.get("DefinitionName") or "") + ")",
		"locationTierOrdinal": r.get("TierOrdinal"),
		"isConsumptionPoint":  bool(r.get("IsConsumptionPoint")),
		"minQuantity":         r.get("MinQuantity"),
		"maxQuantity":         r.get("MaxQuantity"),
		"defaultQuantity":     r.get("DefaultQuantity"),
	})
self.view.custom.state = {"selected": {"rows": loaded}, "editDraft": {"rows": [dict(r) for r in loaded]}}

itemId = self.view.params.value
if not itemId:
	BlueRidge.Common.Notify.toast("No item selected", "Pick an item before saving.", "warning")
	return
draft = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.state.editDraft) or {}
rows = draft.get("rows") or []
result = BlueRidge.Parts.Eligibility.handleSaveAll(itemId, rows)
BlueRidge.Common.Ui.notifyResult(result, "Eligibility saved")
if result and result.get("Status"):
	self.load()

